@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h2 class="mb-3">Project Board</h2>

@if (_loading)
{
    <div class="d-flex justify-content-center py-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading…</span>
        </div>
    </div>
}
else if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @_error
        <button class="btn btn-sm btn-outline-danger ms-3" @onclick="LoadTasksAsync">Retry</button>
    </div>
}
else
{
    <!-- Stats bar -->
    <div class="row g-2 mb-3">
        <div class="col"><div class="card text-center p-2"><small class="text-muted">Total</small><strong>@_allTasks.Count</strong></div></div>
        <div class="col"><div class="card text-center p-2"><small class="text-muted">To Do</small><strong>@GetColumnTasks("To Do").Count</strong></div></div>
        <div class="col"><div class="card text-center p-2"><small class="text-muted">In Progress</small><strong>@GetColumnTasks("In Progress").Count</strong></div></div>
        <div class="col"><div class="card text-center p-2"><small class="text-muted">Done</small><strong>@GetColumnTasks("Done").Count</strong></div></div>
        <div class="col"><div class="card text-center p-2"><small class="text-muted">Overdue</small><strong class="text-danger">@_allTasks.Count(t => t.DueDate.Date < DateTime.Today)</strong></div></div>
    </div>

    <!-- Search bar -->
    <div class="mb-3">
        <input type="text" class="form-control" placeholder="Search tasks by title…" @bind="_searchTerm" @bind:event="oninput" />
    </div>

    <!-- Columns -->
    <div class="row g-3">
        @foreach (var column in _columns)
        {
            var tasks = GetFilteredColumnTasks(column);
            var colIndex = Array.IndexOf(_columns, column);

            <div class="col-md-4">
                <div class="card h-100">
                    <div class="card-header d-flex justify-content-between align-items-center">
                        <strong>@column</strong>
                        <span class="badge bg-secondary">@tasks.Count</span>
                    </div>
                    <div class="card-body d-flex flex-column gap-2 overflow-auto" style="max-height:60vh;">
                        @foreach (var task in tasks)
                        {
                            <div class="card shadow-sm">
                                <div class="card-body p-2">
                                    <h6 class="card-title mb-1">@task.Title</h6>
                                    <p class="mb-1 text-muted small">@task.Assignee</p>
                                    <div class="d-flex justify-content-between align-items-center mb-1">
                                        <span class="badge @GetPriorityClass(task.Priority)">@task.Priority</span>
                                        <small class="text-muted">@task.DueDate.ToString("MMM dd")</small>
                                    </div>
                                    <div class="d-flex gap-1">
                                        @if (colIndex > 0)
                                        {
                                            <button class="btn btn-outline-secondary btn-sm flex-fill"
                                                    disabled="@_updating"
                                                    @onclick="() => MoveTaskAsync(task.Id, _columns[colIndex - 1])">
                                                ← Move Left
                                            </button>
                                        }
                                        @if (colIndex < _columns.Length - 1)
                                        {
                                            <button class="btn btn-outline-secondary btn-sm flex-fill"
                                                    disabled="@_updating"
                                                    @onclick="() => MoveTaskAsync(task.Id, _columns[colIndex + 1])">
                                                Move Right →
                                            </button>
                                        }
                                    </div>
                                </div>
                            </div>
                        }

                        @if (_addingColumn == column)
                        {
                            <div class="card border-primary">
                                <div class="card-body p-2">
                                    <div class="mb-2">
                                        <input type="text" class="form-control form-control-sm" placeholder="Title" @bind="_newTitle" />
                                    </div>
                                    <div class="mb-2">
                                        <input type="text" class="form-control form-control-sm" placeholder="Assignee" @bind="_newAssignee" />
                                    </div>
                                    <div class="mb-2">
                                        <select class="form-select form-select-sm" @bind="_newPriority">
                                            <option value="High">High</option>
                                            <option value="Medium">Medium</option>
                                            <option value="Low">Low</option>
                                        </select>
                                    </div>
                                    <div class="mb-2">
                                        <input type="date" class="form-control form-control-sm" @bind="_newDueDate" />
                                    </div>
                                    <div class="d-flex gap-1">
                                        <button class="btn btn-primary btn-sm flex-fill" disabled="@_saving" @onclick="SaveNewTaskAsync">Save</button>
                                        <button class="btn btn-secondary btn-sm flex-fill" disabled="@_saving" @onclick="CancelAdd">Cancel</button>
                                    </div>
                                </div>
                            </div>
                        }
                    </div>
                    <div class="card-footer">
                        <button class="btn btn-outline-primary btn-sm w-100" @onclick="() => StartAdd(column)">+ Add Task</button>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    private readonly string[] _columns = ["To Do", "In Progress", "Done"];
    private List<TaskItem> _allTasks = new();
    private string _searchTerm = string.Empty;
    private bool _loading = true;
    private bool _updating;
    private bool _saving;
    private string? _error;

    // Add-task form state
    private string? _addingColumn;
    private string _newTitle = string.Empty;
    private string _newAssignee = string.Empty;
    private string _newPriority = "Medium";
    private DateTime _newDueDate = DateTime.Today.AddDays(7);

    protected override async Task OnInitializedAsync()
    {
        await LoadTasksAsync();
    }

    private async Task LoadTasksAsync()
    {
        try
        {
            _loading = true;
            _error = null;
            _allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private List<TaskItem> GetColumnTasks(string status) =>
        _allTasks.Where(t => t.Status == status).ToList();

    private List<TaskItem> GetFilteredColumnTasks(string status)
    {
        var tasks = GetColumnTasks(status);
        if (!string.IsNullOrWhiteSpace(_searchTerm))
        {
            tasks = tasks.Where(t => t.Title.Contains(_searchTerm, StringComparison.OrdinalIgnoreCase)).ToList();
        }
        return tasks;
    }

    private static string GetPriorityClass(string priority) => priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };

    private async Task MoveTaskAsync(int taskId, string newStatus)
    {
        try
        {
            _updating = true;
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var task = _allTasks.First(t => t.Id == taskId);
            _allTasks[_allTasks.IndexOf(task)] = task with { Status = newStatus };
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _updating = false;
        }
    }

    private void StartAdd(string column)
    {
        _addingColumn = column;
        _newTitle = string.Empty;
        _newAssignee = string.Empty;
        _newPriority = "Medium";
        _newDueDate = DateTime.Today.AddDays(7);
    }

    private void CancelAdd() => _addingColumn = null;

    private async Task SaveNewTaskAsync()
    {
        if (string.IsNullOrWhiteSpace(_newTitle) || _addingColumn is null) return;

        try
        {
            _saving = true;
            var created = await TaskService.CreateTaskAsync(_newTitle, _newAssignee, _newPriority, _newDueDate);
            // If the task was created with a default status, adjust to the target column
            if (created.Status != _addingColumn)
            {
                await TaskService.UpdateTaskStatusAsync(created.Id, _addingColumn);
                created = created with { Status = _addingColumn };
            }
            _allTasks.Add(created);
            _addingColumn = null;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _saving = false;
        }
    }
}

